create or replace function crm.enforce_contact_company_department()
returns trigger
language plpgsql
as $$
declare
  dept_company uuid;
begin
  if new.crm_department_id is null then
    return new;
  end if;

  select company_id into dept_company
  from crm.department
  where id = new.crm_department_id;

  if dept_company is null then
