        </SheetContent>
      </Sheet>

      <div className="flex min-w-0 flex-1 flex-col">
        <AppHeader
          onOpenMobileNav={() => setMobileNav(true)}
          onOpenSearch={() => setSearch(true)}
          theme={theme}
