    queryClient.setQueriesData<Buyer[]>({ queryKey: [...crmKeys.all, 'allContacts'] }, optimistic)
    queryClient.setQueriesData<Buyer[]>({ queryKey: [...crmKeys.all, 'ingestedContacts'] }, optimistic)
    try {
